func TestNewPolicyQuotaController(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource(10)

	controller := NewPolicyQuotaController(log, 10, mockRes)

	assert.NotNil(t, controller)
	assert.Equal(t, 10, controller.maxPerNamespace)
	assert.NotNil(t, controller.namespacePolicyCnt)
}

func TestCheckQuota_NoQuotaExceeded(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource(10)

	controller := NewPolicyQuotaController(log, 5, mockRes)

	// Initially no policies
	err := controller.CheckQuota("default")
	assert.NoError(t, err)

	// Add some policies manually
	controller.mu.Lock()
	controller.namespacePolicyCnt["default"] = 3
	controller.mu.Unlock()

	// Check quota with count below max
	err = controller.CheckQuota("default")
	assert.NoError(t, err)
}

func TestCheckQuota_QuotaExceeded(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource(10)

	controller := NewPolicyQuotaController(log, 5, mockRes)

	// Add policies at the max
	controller.mu.Lock()
	controller.namespacePolicyCnt["default"] = 5
	controller.mu.Unlock()

	// Check quota when at max
	err := controller.CheckQuota("default")
	assert.Error(t, err)
	assert.Contains(t, err.Error(), "policy quota exceeded")
}

func TestCheckQuota_ClusterWidePolicy(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource(10)

	controller := NewPolicyQuotaController(log, 5, mockRes)

	// Check quota for cluster-wide policy (empty namespace)
	err := controller.CheckQuota("")
	assert.NoError(t, err)
}

func TestGetNamespacePolicyCount(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource(10)

	controller := NewPolicyQuotaController(log, 10, mockRes)

	// Initially should be 0
	count := controller.GetNamespacePolicyCount("default")
	assert.Equal(t, 0, count)

	// Add policies
	controller.mu.Lock()
	controller.namespacePolicyCnt["default"] = 5
	controller.mu.Unlock()

	count = controller.GetNamespacePolicyCount("default")
	assert.Equal(t, 5, count)
}

func TestResetNamespace(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource(10)

	controller := NewPolicyQuotaController(log, 10, mockRes)

	// Add policies
	controller.mu.Lock()
	controller.namespacePolicyCnt["default"] = 5
	controller.mu.Unlock()

	// Reset namespace
	controller.ResetNamespace("default")

	count := controller.GetNamespacePolicyCount("default")
	assert.Equal(t, 0, count)
}

func TestHandleUpsert(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource(10)

	controller := NewPolicyQuotaController(log, 10, mockRes)

	cnp := newTestCNP("test-policy", "default")
	err := controller.handleUpsert(cnp)

	assert.NoError(t, err)
	count := controller.GetNamespacePolicyCount("default")
	assert.Equal(t, 1, count)
}

func TestHandleUpsert_ClusterWidePolicy(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource(10)

	controller := NewPolicyQuotaController(log, 10, mockRes)

	cnp := newTestCNP("test-policy", "")
	err := controller.handleUpsert(cnp)

	assert.NoError(t, err)
	// Cluster-wide policies should not be counted
	count := controller.GetNamespacePolicyCount("")
	assert.Equal(t, 0, count)
}

func TestHandleDelete(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource(10)

	controller := NewPolicyQuotaController(log, 10, mockRes)

	// Add a policy first
	cnp := newTestCNP("test-policy", "default")
	_ = controller.handleUpsert(cnp)

	assert.Equal(t, 1, controller.GetNamespacePolicyCount("default"))

	// Delete the policy
	err := controller.handleDelete(cnp)

	assert.NoError(t, err)
	count := controller.GetNamespacePolicyCount("default")
	assert.Equal(t, 0, count)
}

func TestHandleDelete_NotFound(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource(10)

	controller := NewPolicyQuotaController(log, 10, mockRes)

	cnp := newTestCNP("test-policy", "default")
	// Delete without adding first - should not panic or error
	err := controller.handleDelete(cnp)

	assert.NoError(t, err)
	count := controller.GetNamespacePolicyCount("default")
	assert.Equal(t, 0, count)
}

func TestRun_ContextCancelled(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource(10)

	controller := NewPolicyQuotaController(log, 10, mockRes)

	ctx, cancel := context.WithCancel(context.Background())

	// Run in a goroutine
	done := make(chan error, 1)
	go func() {
		done <- controller.Run(ctx)
	}()

	// Cancel the context
	cancel()

	// Wait for the controller to exit
	err := <-done
	require.Error(t, err)
	assert.Equal(t, context.Canceled, err)
}

func TestRun_EventProcessing(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource(10)

	controller := NewPolicyQuotaController(log, 10, mockRes)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Run in a goroutine
	done := make(chan error, 1)
	go func() {
		done <- controller.Run(ctx)
	}()

	// Send a sync event
	syncDone := make(chan error, 1)
	mockRes.events <- &mockEvent{
		kind: resource.Sync,
		done: func(err error) {
			syncDone <- err
		},
	}

	// Wait for sync event to be processed
	err := <-syncDone
	assert.NoError(t, err)

	// Send an upsert event
	cnp := newTestCNP("test-policy", "default")
	upsertDone := make(chan error, 1)
	mockRes.events <- &mockEvent{
		kind:   resource.Upsert,
		object: cnp,
		done: func(err error) {
			upsertDone <- err
		},
	}

	// Wait for upsert event to be processed
	err = <-upsertDone
	assert.NoError(t, err)
	assert.Equal(t, 1, controller.GetNamespacePolicyCount("default"))

	// Send a delete event
	deleteDone := make(chan error, 1)
	mockRes.events <- &mockEvent{
		kind:   resource.Delete,
		object: cnp,
		done: func(err error) {
			deleteDone <- err
		},
	}

	// Wait for delete event to be processed
	err = <-deleteDone
	assert.NoError(t, err)
	assert.Equal(t, 0, controller.GetNamespacePolicyCount("default"))

	// Cancel context to stop the controller
	cancel()

	// Wait for the controller to exit
	runErr := <-done
	require.Error(t, runErr)
	assert.Equal(t, context.Canceled, runErr)
}
